// Interface for RequestOptions
interface RequestOptions {
  url: string;
  type: 'GET' | 'POST' | 'PUT' | 'DELETE' | 'PATCH';
  timeout?: number;
  headers?: string | { [name: string]: string | string[] };
  contentType?: string;
  data?: any;
  params?: { [param: string]: string  };
  cors?: boolean;
  externalRequest?: boolean;
}

// Type guard function
export default function isRequestOptions(obj: any): obj is RequestOptions {
  return (
      typeof obj.url === 'string' &&
      ['GET', 'POST', 'PUT', 'DELETE', 'PATCH'].includes(obj.type) &&
      (typeof obj.timeout === 'undefined' || typeof obj.timeout === 'number') &&
      (typeof obj.headers === 'undefined' || typeof obj.headers === 'string' || isHeadersObject(obj.headers)) &&
      (typeof obj.contentType === 'undefined' || typeof obj.contentType === 'string') &&
      (typeof obj.data === 'undefined' || true) && // Can be any type
      (typeof obj.params === 'undefined' || isParamsObject(obj.params)) &&
      (typeof obj.cors === 'undefined' || typeof obj.cors === 'boolean') &&
      (typeof obj.externalRequest === 'undefined' || typeof obj.externalRequest === 'boolean')
  );
}

// Helper functions for type guard
function isHeadersObject(obj: any): obj is { [name: string]: string | string[] } {
  if (typeof obj === 'object' && obj !== null) {
      for (const key in obj) {
          const value = obj[key];
          if (!(typeof value === 'string' || Array.isArray(value))) {
              return false;
          }
      }
      return true;
  }
  return false;
}

function isParamsObject(obj: any): obj is { [param: string]: string } {
  if (typeof obj === 'object' && obj !== null) {
      for (const key in obj) {
          const value = obj[key];
          if (typeof value !== 'string') {
              return false;
          }
      }
      return true;
  }
  return false;
}