/* global URL */
import pkgJson from '../package.json'
import { when, isObject, isString, debounce } from './utils'
import IdleState from './utils/idleState'
import Tracker from './tracker'
import NativePromise from 'native-promise-only'
import isRequestOptions from './utils/request-option'
import lodash from 'lodash'
import moment from 'moment-timezone/builds/moment-timezone-with-data-1970-2030.min'
import { v4 as uuid } from 'uuid'

// Direct package exports

const Promise = window.Promise || NativePromise

export const IFRAME_SESSION_TIMEOUT = 5 * 60 * 1000 // Set timeout for iframe sessions to 5 minutes.
export const PROMISE_TIMEOUT = 10000
// 10 seconds, see ZD#4058685
export const PROMISE_TIMEOUT_LONG = 5 * 60 * 1000
// Set a high timeout threshold to allow us to better gauge the time taken for successful requests

// Constants for optimized performance
const NO_TIMEOUT_ACTIONS = ['ui.create']
const ZAF_EVENT = /^zuper\./
const ACTION_ARGS_REGEX = /:\w+(,?\w+)*((\.(show|hide|enable|disable))|(\\?\.\w*))?/g
const SECONDS_DIVISOR = 1000
const TIME_RANGE_DIVISOR = 10000
const WHITELISTED_ORIGINS = [
  /^https?:\/\/127.0.0.1(:\d+)?$/,
  /^https?:\/\/localhost(:\d+)?$/,
  /^https:\/\/.+\.zuperpro\.com$/,
  /^https:\/\/.+\.zuper\.dev$/
]

// Common message strings
const MSG_IFRAME_HANDSHAKE = 'iframe.handshake'
const MSG_APP_REGISTERED = 'app.registered'
const MSG_SESSION_LIVE = 'session.live'
const MSG_TRACK = '__track__'

// Message queue configuration
// Default message queue configuration - can be overridden per client
const MESSAGE_QUEUE_CONFIG = {
  MAX_QUEUE_SIZE: 1000,
  BATCH_SIZE: 10,
  THROTTLE_DELAY: 16, // ~60fps
  MAX_RETRIES: 3,
  RETRY_DELAY: 100,
  enableLogging: true // 'silent', true, 'verbose'
}

// Helper function to merge configurations with validation
function mergeQueueConfig(baseConfig, userConfig) {
  const merged = Object.assign({}, baseConfig, userConfig)

  // Validate and clamp values to safe ranges
  merged.MAX_QUEUE_SIZE = Math.max(1, Math.min(merged.MAX_QUEUE_SIZE || 1000, 10000))
  merged.THROTTLE_DELAY = Math.max(1, Math.min(merged.THROTTLE_DELAY || 16, 1000))
  merged.BATCH_SIZE = Math.max(1, Math.min(merged.BATCH_SIZE || 10, 100))
  merged.MAX_RETRIES = Math.max(0, Math.min(merged.MAX_RETRIES || 3, 10))
  merged.RETRY_DELAY = Math.max(10, Math.min(merged.RETRY_DELAY || 100, 5000))

  return merged
}

const pendingPromises = {}
const ids = {}
const SINGLETON_HANDLER_ACTION_PREFIXES = ['pre_event'];

// Pre-allocated common error objects for performance
const COMMON_ERRORS = {
  INVOCATION_TIMEOUT: new Error('Invocation request timeout'),
  SETTER_REQUIRES_VALUE: new Error('The setter requires a value'),
  PROP_REQUIRES_VALUE: new Error('The prop requires a value'),
  DISPATCH_REQUIRES_VALUE: new Error('dispatch requires a value'),
  ACCEPT_REQUIRES_VALUE: new Error('accept requires a value'),
  GET_METHOD_ACCEPTS_STRING: new Error('The get method accepts a string or object.'),
  EXIST_METHOD_ACCEPTS_STRING: new Error('The exist method accepts a string.'),
  SET_METHOD_ACCEPTS_PAIRS: new Error('The set method accepts a key and value pair, or an object of key and value pairs.'),
  PROP_METHOD_ACCEPTS_PAIRS: new Error('The prop method accepts a key and value pair, or an object of key and value pairs.'),
  DISPATCH_METHOD_ACCEPTS_PAIRS: new Error('The dispatch method accepts a key and value pair, or an object of key and value pairs.'),
  HANDLE_METHOD_ACCEPTS_PAIRS: new Error('The handle method accepts a key and value pair, or an object of key and value pairs.'),
  INVOKE_STRING_ARGUMENTS: new Error('Invoke supports string arguments or an object with array of strings.'),
  INSTANCE_EXPECTS_STRING: new Error('The instance method expects an `instanceGuid` string.'),
  PARENT_INSTANCES_ONLY: new Error('This method can only be accessed by parent instances, not by component instances.'),
  REQUEST_OPTIONS_INTERFACE: new Error('options does not match RequestOptions interface'),
  ILLEGAL_BULK_CALL: new Error('Illegal bulk call - `ui.create` must be called separately.')
};

// Message Queue Class for handling postMessage limitations
class MessageQueue {
  constructor(client) {
    this.client = client
    this.config = client._queueConfig || MESSAGE_QUEUE_CONFIG
    this.queue = []
    this.isProcessing = false
    this.lastSentTime = 0
    this.throttleTimer = null
  }

  enqueue(msg, forceReady = false, retries = 0) {
    // Check queue size limit
    if (this.queue.length >= this.config.MAX_QUEUE_SIZE) {
      console.warn('ZAF SDK: Message queue full, dropping oldest messages')
      this.queue.shift() // Remove oldest message
    }

    this.queue.push({
      msg,
      forceReady,
      retries,
      timestamp: Date.now(),
      id: nextIdFor('message')
    })

    this.processQueue()
  }

  processQueue() {
    // Use atomic check-and-set to prevent race conditions
    if (this.isProcessing || this.queue.length === 0) {
      return
    }

    // Atomic operation to set processing state
    this.isProcessing = true

    // Clear any existing throttle timer to prevent conflicts
    if (this.throttleTimer) {
      clearTimeout(this.throttleTimer)
      this.throttleTimer = null
    }

    // Throttle processing to avoid overwhelming the browser
    const now = Date.now()
    const timeSinceLastSent = now - this.lastSentTime

    if (timeSinceLastSent < this.config.THROTTLE_DELAY) {
      const delay = this.config.THROTTLE_DELAY - timeSinceLastSent
      this.throttleTimer = setTimeout(() => {
        this.isProcessing = false
        this.processQueue()
      }, delay)
      return
    }

    this.processBatch()
  }

  processBatch() {
    const batch = this.queue.splice(0, this.config.BATCH_SIZE)

    batch.forEach(item => {
      if (this.canSendMessage(item)) {
        try {
          this.client._source.postMessage(item.msg, this.client._origin)
          this.lastSentTime = Date.now()
        } catch (error) {
          this.logMessage('warn', 'ZAF SDK: Failed to send message', { error: error.message, item })
          this.handleFailedMessage(item)
        }
      } else {
        // Re-queue if not ready
        this.queue.unshift(item)
      }
    })

    // Clear throttle timer and reset processing state atomically
    if (this.throttleTimer) {
      clearTimeout(this.throttleTimer)
      this.throttleTimer = null
    }
    this.isProcessing = false

    // Continue processing if there are more messages
    if (this.queue.length > 0) {
      this.throttleTimer = setTimeout(() => this.processQueue(), this.config.THROTTLE_DELAY)
    }
  }

  canSendMessage(item) {
    return (this.client.ready || item.forceReady) &&
           this.client._source &&
           this.client._origin
  }

  handleFailedMessage(item) {
    if (item.retries < this.config.MAX_RETRIES) {
      // Retry with backoff
      const retryDelay = this.config.RETRY_DELAY * Math.pow(2, item.retries)
      setTimeout(() => {
        this.enqueue(item.msg, item.forceReady, item.retries + 1)
      }, retryDelay)
    } else {
      // Ensure complete cleanup of failed message object
      this.logMessage('error', 'ZAF SDK: Message failed after max retries', {
        msg: item.msg,
        retries: item.retries,
        timestamp: item.timestamp
      })
      // Clear references to prevent memory leaks
      item.msg = null
      item = null
    }
  }

  logMessage(level, message, data = {}) {
    // Use client's logging configuration if available, otherwise fall back to console
    if (this.client._queueConfig && this.client._queueConfig.enableLogging !== false) {
      const logMethod = console[level] || console.log
      if (this.client._queueConfig.enableLogging === 'verbose' || level === 'error') {
        logMethod(message, data)
      } else if (level === 'warn' && this.client._queueConfig.enableLogging !== 'silent') {
        logMethod(message)
      }
    }
  }

  clear() {
    this.queue = []
    if (this.throttleTimer) {
      clearTimeout(this.throttleTimer)
      this.throttleTimer = null
    }
    this.isProcessing = false
  }

  getQueueStatus() {
    return {
      queueLength: this.queue.length,
      isProcessing: this.isProcessing,
      oldestMessageAge: this.queue.length > 0 ? Date.now() - this.queue[0].timestamp : 0
    }
  }
}

// // export Promise!
window.Promise = Promise

// @internal
// #timeoutReject(rejectionFn, name, client, params)
//
// Reject a request if required, given the rejection function, name (get, set or invoke)
// and arguments to that request. Falls back to 10 second timeout with few exceptions.
//
function timeoutReject (client, reject, name, paramsArray, resolve) {
  const actions = collateActions(name, paramsArray)
  switch (name) {
    case 'invoke': {
      const matches = paramsArray.filter((action) => {
        return NO_TIMEOUT_ACTIONS.indexOf(action) !== -1
      })
      const allWhitelisted = matches.length === paramsArray.length
      if (allWhitelisted) {
        return NaN // timer IDs are numbers; embrace the JavaScript 😬
      } else {
        const notAllWhitelisted = matches.length !== 0
        if (notAllWhitelisted) {
          throw COMMON_ERRORS.ILLEGAL_BULK_CALL
        }
        return defaultTimer(client, actions, reject, resolve)
      }
    }
    default: {
      return defaultTimer(client, actions, reject, resolve)
    }
  }
}

function defaultTimer (client, actions, callback, resolve) {
  return setTimeout(() => {
    trackSDKRequestTimeout(client, actions, PROMISE_TIMEOUT)
    // Silently resolve instead of rejecting after 10 seconds
    if (resolve) {
      resolve(undefined) // Resolve with undefined for silent completion
    } else {
      callback(COMMON_ERRORS.INVOCATION_TIMEOUT)
    }
  }, PROMISE_TIMEOUT) // Use 10 second timeout instead of 5 minutes
}

export function collateActions (name, params) { return params.map(action => `${name}-${action}`) }

export function stripActionArgs (action) {
  // Capture:
  // 1. single or multiple comma-delimited arguments following an initial colon, and
  // 2. non-whitelisted, unescaped words following a period (i.e. file extensions in the case of assetURL calls)
  // Return :arg.field_modifier, where field modifier is (optionally) one of 'show', 'hide', 'enable' or 'disable'
  return action.replace(ACTION_ARGS_REGEX, ':arg$3')
}

export function timeMsToSecondsRange (value, upperLimit = PROMISE_TIMEOUT) {
  if (value >= upperLimit) return `${upperLimit / SECONDS_DIVISOR}-`
  const lowerRangeBound = value - (value % TIME_RANGE_DIVISOR)
  return `${lowerRangeBound / SECONDS_DIVISOR}-${(lowerRangeBound + TIME_RANGE_DIVISOR) / SECONDS_DIVISOR}`
}

export function trackSDKRequestTimeout (client, actions, requestResponseTime) {
  const actionsTags = actions.map(action => `action:${stripActionArgs(action)}`)
  const responseTimeTag = `request_response_time:${timeMsToSecondsRange(requestResponseTime)}`
  client.postMessage(MSG_TRACK, {
    event_name: 'sdk_request_timeout',
    event_type: 'increment',
    data: 1,
    tags: actionsTags.concat(responseTimeTag)
  })
}

function nextIdFor (name) {
  if (isNaN(ids[name])) {
    ids[name] = 0
  }
  return ++ids[name]
}

// @internal
// #### rawPostMessage(client, msg, forceReady)
//
// Post a message to the hosting frame using message queue for reliability.
// If the client is not ready and forceReady is not specified, it will queue the message.
//
function rawPostMessage (client, msg, forceReady) {
  // Initialize message queue if not exists
  if (!client._messageQueue) {
    client._messageQueue = new MessageQueue(client)
  }

  // Use queue for reliable message delivery
  client._messageQueue.enqueue(msg, forceReady)
}

// @internal
// #### wrappedPostMessage(name, params)
//
// Wraps post message with a request/response mechanism using Promises.
// Must be invoked in the context of a Client.
//
// ##### Arguments
//
//   * `name` the name of the request to make (get/set/invoke)
//   * `params` parameters of the request (an array for get, and an object for set/invoke)
//
function wrappedPostMessage (name, params) {
  const id = nextIdFor('promise')
  let timeoutId, promiseStartTime
  const paramsArray = Array.isArray(params) ? params : Object.keys(params)
  const actions = collateActions(name, paramsArray)
  const client = this

  const promise = new Promise((resolve, reject) => {
    promiseStartTime = window.performance.now()

    // Time out the promise to ensure it will be garbage collected if nobody responds
    timeoutId = timeoutReject(client, reject, name, paramsArray, resolve)
    pendingPromises[id] = { resolve, reject }

    const msg = JSON.stringify({
      id: id,
      request: name,
      params: params,
      appGuid: client._appGuid,
      instanceGuid: client._instanceGuid
    })
    rawPostMessage(client, msg)
  })

  const trackTimeoutWithResolutionTime = () => {
    const promiseResolutionTime = window.performance.now() - promiseStartTime
    if (promiseResolutionTime > PROMISE_TIMEOUT) {
      trackSDKRequestTimeout(client, actions, promiseResolutionTime)
    }
  }

  // ensure promise is cleaned up when resolved/rejected, track request performance for resolved promises
  return promise.then(
    removePromise.bind(null, { id, timeoutId, trackTimeoutWithResolutionTime }),
    removePromise.bind(null, { id, timeoutId })
  )
}

function createError (error) {
  if (error.path) { error.message = '"' + error.path + '" ' + error.message }
  const err = new Error(error.message)
  err.name = error.name
  err.stack = error.stack
  return err
}

function removePromise (options, args) {
  clearTimeout(options.timeoutId)
  delete pendingPromises[options.id]
  options.trackTimeoutWithResolutionTime && options.trackTimeoutWithResolutionTime()
  if (args instanceof Error) throw args
  return args
}

function isValidEvent (client, event) {
  return client && client._origin === event.origin && client._source === event.source
}

function triggerEvent (client, eventName, data) {
  if (!client._messageHandlers[eventName]) { return false }
  client._messageHandlers[eventName].forEach((handler) => {
    handler(data)
  })
}

function finalizePendingPromise (pendingPromise, data) {
  if (data.error) {
    const error = data.error.name ? createError(data.error) : data.error
    pendingPromise.reject(error)
  } else {
    pendingPromise.resolve(data.result)
  }
}

function postReplyWith (client, key, msg) {
  if (client._repliesPending[key]) { return }
  msg.key = 'iframe.reply:' + key
  client._repliesPending[key] = true
  return when(client._messageHandlers[key]).then(
    rawPostMessage.bind(null, client, msg)
  ).catch((reason) => {
    // if the handler throws an error we want to send back its message, but
    // Error objects don't pass through the postMessage boundary.
    const rejectMessage = reason instanceof Error ? reason.message : reason
    msg.error = {
      msg: rejectMessage
    }
    rawPostMessage(client, msg)
  }).then(() => {
    delete client._repliesPending[key]
  })
}

function getMessageRecipient (client, recipientGuid) {
  let messageRecipient = client

  if (recipientGuid && recipientGuid !== client._instanceGuid) {
    messageRecipient = client._instanceClients[recipientGuid]

    if (!messageRecipient) {
      throw Error('[ZAF SDK] Could not find client for instance ' + recipientGuid)
    }
  }

  return messageRecipient
}

function messageHandler (client, event) {
  if (!isValidEvent(client, event)) { return }

  let data = event.data

  if (!data) { return }

  if (typeof data === 'string') {
    try {
      data = JSON.parse(event.data)
    } catch (e) {
      return e
    }
  }

  const clientRecipient = getMessageRecipient(client, data.instanceGuid)
  let pendingPromise

  if (data.id && (pendingPromise = pendingPromises[data.id])) {
    finalizePendingPromise(pendingPromise, data)
  } else if (ZAF_EVENT.test(data.key)) {
    const key = data.key.replace(ZAF_EVENT, '')
    const msg = { appGuid: client._appGuid }

    if (data.needsReply) {
      return postReplyWith(clientRecipient, key, msg)
    } else {
      triggerEvent(clientRecipient, key, data.message)
    }
  }
}

// When doing singular operations and we retrieve an error this function will throw that error
function processResponse (path, result) {
  const isSingularOperation = typeof path === 'string'

  if (!isSingularOperation) {
    return result
  }

  // Guard against undefined/null result - this can happen if server doesn't send result field
  if (!result) {
    return result
  }

  // CRUFT: When framework starts always appending errors we can remove the extra results.errors check
  const err = result.errors && result.errors[path]
  if (err) {
    throw createError(err)
  }

  return result
}

function isOriginValid (origin) {
  if (origin) {
    for (let i = 0; i < WHITELISTED_ORIGINS.length; i++) {
      if (WHITELISTED_ORIGINS[i].test(origin)) {
        return true
      }
    }
  }

  return false
}

function clearDocument () {
  const doc = document
  doc.body = doc.createElement('body')

  const iframeHead = doc.head
  iframeHead && iframeHead.remove()
}

function appendErrorToBody (errorMsg) {
  var errorElement = document.createElement('h3')
  var errorTextNode = document.createTextNode(errorMsg)

  errorElement.appendChild(errorTextNode)
  document.body.appendChild(errorElement)
}

export default class Client {
  constructor (options) {
    this._parent = options.parent
    this._origin = options.origin || (this._parent && this._parent._origin)
    this._source = options.source || (this._parent && this._parent._source) || window.parent
    this._appGuid = options.appGuid || (this._parent && this._parent._appGuid)
    this._instanceGuid = options.instanceGuid || this._appGuid

    // Message queue configuration - can be overridden by options with validation
    this._queueConfig = mergeQueueConfig(MESSAGE_QUEUE_CONFIG, options.messageQueue || {})
    this._messageHandlers = {}
    this._repliesPending = {}
    this._instanceClients = {}
    this._metadata = null
    this._context = options.context || null
    this._idleState = null
    this._messageQueue = null
    this.ready = false
    if(!this._parent) {
      this.packages = {
        'lodash': lodash,
        'moment': moment,
        'uuid': uuid
      }
    }

    if (!isOriginValid(this._origin)) {
      const originHostname = new URL(this._origin).hostname
      this.postMessage(MSG_TRACK, {
        event_name: 'invalid_sdk_origin',
        event_type: 'increment',
        data: 1,
        tags: ['origin:' + originHostname]
      })

      clearDocument()
      appendErrorToBody(`Invalid domain ${this._origin}`)
    }

    this.on(MSG_APP_REGISTERED, (data) => {
      this.ready = true
      this._metadata = data.metadata
      this._context = data.context
      this._idleState = new IdleState()
      this._idleState.addObserver(debounce(() => {
        this.postMessage(MSG_SESSION_LIVE)
      }, 1000))
    }, this)



    this.on('context.updated', (context) => {
      this._context = context
    }, this)

    
    if (this._parent) {
      this.ready = this._parent.ready
      return this // shortcut handshake
    }

    const tracker = new Tracker(this)
    tracker.setup()
    window.addEventListener('message', messageHandler.bind(null, this))
    this.postMessage(MSG_IFRAME_HANDSHAKE, { version: pkgJson.version })
  }

  /**
   * ### Client Object
   *
   * #### client.postMessage(name, [data])
   *
   * Allows you to send message events to the Zuper app.
   *
   * ##### Arguments
   *
   *   * `name` the name of the message event. This determines the name of the iframe
   *     event your app will receive. For example, if you set this to 'hello', your app will receive
   *     the event 'iframe.hello'
   *   * `data` (optional) a JSON object with any data that you want to pass along with the
   *     event
   *
   * ```javascript
   * const client = ZAFClient.init();
   * client.postMessage('hello', { awesome: true });
   * ``
   */
  postMessage (name, data) {
    const msg = JSON.stringify({ key: name, message: data, appGuid: this._appGuid, instanceGuid: this._instanceGuid })
    rawPostMessage(this, msg, name === MSG_IFRAME_HANDSHAKE)
  }

  /**
   * #### client.on(name, handler, [context])
   *
   * Allows you to add handlers to a framework event. You can add as many handler as you wish.
   * They will be executed in the order they were added.
   *
   * ##### Arguments
   *
   *   * `name` the name of the framework event you want to listen to. This can be
   *     [framework](./events.html#framework-events), [request](./events.html#request-events), or
   *     [custom](./events.html#custom-events) events. Your iframe can listen to any events your app
   *     receives, apart from DOM events. You don't need to register these events in the app first
   *   * `handler` a function to be called when this event fires. You can expect to receive the same
   *     event object your app would receive, parsed as JSON
   *   * `context` (optional) the value of `this` within your handler
   *
   * ```javascript
   * const client = ZAFClient.init();
   * client.on('app.registered', (e) => {
   *   // go nuts
   * });
   * ```
   *
   * Note: As soon as communication with the Zuper app is established, the SDK triggers an
   * `app.registered` event. You can add as many handlers to `app.registered` as you like. They're
   * called immediately after the `init` callback
   */
  on (name, handler, context) {
    if (typeof handler === 'function') {
      handler = context
        ? handler.bind(context)
        : handler

      this._messageHandlers[name] = this._messageHandlers[name] || []

      if(SINGLETON_HANDLER_ACTION_PREFIXES.some(prefix => name.includes(prefix))){
        if(this._messageHandlers[name] && this._messageHandlers[name].length > 0){
          throw new Error(`handler for action "${name}" is already registered. only one handler is allowed.`);
        }
      }
      this._messageHandlers[name].push(handler)

      if (name !== MSG_APP_REGISTERED) {
        // Subscriber count is needed as the framework will only bind events on the first attached handler
        this.postMessage('iframe.on:' + name, { subscriberCount: this._messageHandlers[name].length })
      }
    }
  }

  /**
   * #### client.off(name, handler)
   *
   * Allows you to remove a handler for a framework event.
   *
   * ##### Arguments
   *
   *   * `name` the name of the event
   *   * `handler` the function you attached earlier with `on`
   *
   * ```javascript
   * const client = ZAFClient.init();
   *
   * client.on('app.registered', function appRegistered(e) {
   *   // do stuff then remove the handler
   *   client.off('app.registered', appRegistered);
   * });
   * ``
   */
  off (name, handler) {
    if (!this._messageHandlers[name]) { return false }
    const index = this._messageHandlers[name].indexOf(handler)
    if (this.has(name, handler)) {
      this._messageHandlers[name].splice(index, 1)
    }

    // Subscriber count is needed as the framework will only unbind events on the last detached handler (count of 0)
    this.postMessage('iframe.off:' + name, { subscriberCount: this._messageHandlers[name].length })
    return handler
  }

  /**
   * #### client.has(name, handler)
   *
   * Returns whether or not an event has the specified handler attached to it.
   *
   * ##### Arguments
   *
   *   * `name` the name of the event
   *   * `handler` the handler you want to test
   *
   * ```javascript
   * const client = ZAFClient.init();
   *
   * client.on('app.registered', function appRegistered(e) {
   *   // do stuff
   * });
   *
   * client.has('app.registered', appRegistered); // true
   * client.has('app.activated', appRegistered); // false
   * ``
   */
  has (name, handler) {
    if (!this._messageHandlers[name]) { return false }
    return this._messageHandlers[name].indexOf(handler) !== -1
  }

  /**
   * #### client.trigger(name, [data])
   *
   * Triggers the specified event on the client.
   *
   * ##### Arguments
   *
   *   * `name` the name of the event you want to trigger
   *   * `data` (optional) data you want to pass to the handler
   *
   * ```javascript
   * const client = ZAFClient.init();
   *
   * client.on('activation', () => {
   *   console.log('activating!')
   * });
   *
   * client.trigger('activation') // activating!
   * ``
   */
  trigger (name, data) {
    this.postMessage('iframe.trigger:' + name, data)
  }

  /**
   * #### client.request(options)
   *
   * Dispatch [requests](./requests) via the Zuper app.
   *
   * ##### Arguments
   *
   *   * `options` the url of the request or an options object containing a url key/value
   *
   * ##### Returns
   *
   * A [Promises/A+](https://promisesaplus.com) conformant `promise` object.
   *
   * ```javascript
   * const client = ZAFClient.init();
   *
   * client.request('/api/v2/tickets.json').then(
   *   (tickets) => {
   *     console.log(tickets);
   *   },
   *   (response) => {
   *     console.error(response.responseText);
   *   }
   * );
   * ``
   */
  request (options) {
    if (this._parent) { return this._parent.request(options) }
    const requestKey = 'request:' + nextIdFor('request')

    return new Promise((resolve, reject) => {
      if(!isRequestOptions(options)){
        throw COMMON_ERRORS.REQUEST_OPTIONS_INTERFACE
      }
      
      let request = {
        'options': options
      }

      const doneEventKey = `${requestKey}.done`
      const failEventKey = `${requestKey}.fail`

      const doneHandler = (evt) => {
        resolve(evt)
        this.off(failEventKey, failHandler)
        this.off(doneEventKey, doneHandler)
      }

      const failHandler = (evt) => {
        reject(evt)
        this.off(failEventKey, failHandler)
        this.off(doneEventKey, doneHandler)
      }

      this.on(doneEventKey, doneHandler)
      this.on(failEventKey, failHandler)

      this.postMessage(requestKey, request)
    })
  }

  instance (instanceGuid) {
    if (!instanceGuid || typeof instanceGuid !== 'string') {
      throw COMMON_ERRORS.INSTANCE_EXPECTS_STRING
    }
    if (instanceGuid === this._instanceGuid) { return this }
    if (this._parent) { return this._parent.instance(instanceGuid) }
    let instanceClient = this._instanceClients[instanceGuid]
    if (!instanceClient) {
      instanceClient = new Client({
        parent: this,
        instanceGuid: instanceGuid
      })
      this._instanceClients[instanceGuid] = instanceClient
    }
    return instanceClient
  }

  metadata () {
    if (this._parent) { return this._parent.metadata() }
    return new Promise((resolve) => {
      if (this._metadata) {
        resolve(this._metadata)
      } else {
        this.on(MSG_APP_REGISTERED, () => {
          resolve(this._metadata)
        })
      }
    })
  }

  context () {
    if (this._context) {
      return Promise.resolve(this._context)
    } else {
      if (this._instanceGuid && this._instanceGuid !== this._appGuid) {
        const key = 'instances.' + this._instanceGuid
        return this.get(key).then((data) => {
          this._context = data[key]
          return this._context
        })
      } else {
        return new Promise((resolve) => {
          this.on(MSG_APP_REGISTERED, (data) => {
            resolve(data.context)
          })
        })
      }
    }
  }

  // Accepts string or array of strings.
  get (path) {
    const paths = [path]

    if (arguments.length > 1 || paths.some((path) => { return !(typeof path == 'object' || typeof path == 'string' )})) {
      throw COMMON_ERRORS.GET_METHOD_ACCEPTS_STRING
    }

    return wrappedPostMessage.call(this, 'get', paths).then(processResponse.bind(null, path))
  }

  isExist (path) {
    const paths = [path]

    if (arguments.length > 1 || paths.some((path) => { return !(typeof path == 'string' )})) {
      throw new Error('The exist method accepts a string.')
    }

    return wrappedPostMessage.call(this, 'isExist', paths).then(processResponse.bind(null, path))
  }

  set (key, val) {
    let obj = key

    if (typeof key === 'string') {
      if (arguments.length === 1) {
        throw COMMON_ERRORS.SETTER_REQUIRES_VALUE
      }
      obj = {}
      obj[key] = val
    }

    if (!isObject(obj) || Array.isArray(obj)) {
      throw COMMON_ERRORS.SET_METHOD_ACCEPTS_PAIRS
    }

    return wrappedPostMessage.call(this, 'set', obj).then(processResponse.bind(null, key))
  }

  prop (key, val) {
    let obj = key

    if (typeof key === 'string') {
      if (arguments.length === 1) {
        throw COMMON_ERRORS.PROP_REQUIRES_VALUE
      }
      obj = {}
      obj[key] = val
    }

    if (!isObject(obj) || Array.isArray(obj)) {
      throw COMMON_ERRORS.PROP_METHOD_ACCEPTS_PAIRS
    }

    return wrappedPostMessage.call(this, 'prop', obj).then(processResponse.bind(null, key))
  }

  invoke (keyOrObject) {
    let obj = {}

    if (typeof keyOrObject === 'string') {
      obj[keyOrObject] = Array.prototype.slice.call(arguments, 1)
    } else if (typeof keyOrObject === 'object') {
      // Validate object
      Object.keys(keyOrObject).forEach((key) => {
        const methodArgs = keyOrObject[key]

        if (!Array.isArray(methodArgs) || methodArgs.some((arg) => { return !isString(arg) })) {
          throw COMMON_ERRORS.INVOKE_STRING_ARGUMENTS
        }
      })

      obj = keyOrObject
    } else {
      throw COMMON_ERRORS.INVOKE_STRING_ARGUMENTS
    }

    return wrappedPostMessage.call(this, 'invoke', obj).then(processResponse.bind(null, keyOrObject))
  }

  dispatch (key, val) {
    let obj = key

    if (typeof key === 'string') {
      if (arguments.length === 1) {
        throw new Error('dispatch requires a value')
      }
      obj = {}
      obj[key] = val
    }

    if (!isObject(obj) || Array.isArray(obj)) {
      throw new Error('The dispatch method accepts a key and value pair, or an object of key and value pairs.')
    }

    return wrappedPostMessage.call(this, 'dispatch', obj).then(processResponse.bind(null, key))
  }

  handle (key, val) {
    if(this._parent){
      throw COMMON_ERRORS.PARENT_INSTANCES_ONLY
    }
    let obj = key
    if (typeof key === 'string') {
      if (arguments.length === 1) {
        throw new Error('accept requires a value')
      }
      obj = {}
      obj[key] = val
    }

    if (!isObject(obj) || Array.isArray(obj)) {
      throw new Error('The handle method accepts a key and value pair, or an object of key and value pairs.')
    }

    return wrappedPostMessage.call(this, 'handle', obj).then(processResponse.bind(null, key))
  }


  reset(key){
    if(this._parent){
      throw COMMON_ERRORS.PARENT_INSTANCES_ONLY
    }

    this.on('app.reset', (data) => {
      this._messageHandlers = {}
      this._repliesPending = {}
      this._instanceClients = {}
      this.ready = true
      this._metadata = data.metadata
      this._context = data.context
      this._idleState = new IdleState()
      this._idleState.addObserver(debounce(() => {
        this.postMessage(MSG_SESSION_LIVE)
      }, 1000))
    }, this)

    return wrappedPostMessage.call(this, 'reset', {}).then(processResponse.bind(null, key))

  }

  /**
   * #### client.getMessageQueueStatus()
   *
   * Returns the current status of the message queue for debugging.
   *
   * ##### Returns
   *
   * An object with queue statistics including length and processing status.
   */
  getMessageQueueStatus() {
    if (!this._messageQueue) {
      return { queueLength: 0, isProcessing: false, oldestMessageAge: 0 }
    }
    return this._messageQueue.getQueueStatus()
  }

  /**
   * #### client.clearMessageQueue()
   *
   * Clears all pending messages in the queue. Use with caution.
   */
  clearMessageQueue() {
    if (this._messageQueue) {
      this._messageQueue.clear()
    }
  }

  /**
   * #### client.flushMessageQueue()
   *
   * Forces immediate processing of queued messages.
   */
  flushMessageQueue() {
    if (this._messageQueue) {
      this._messageQueue.processQueue()
    }
  }

  /**
   * #### client.updateMessageQueueConfig(config)
   *
   * Updates the message queue configuration at runtime.
   *
   * ##### Arguments
   *
   *   * `config` object with queue configuration options
   */
  updateMessageQueueConfig(config) {
    this._queueConfig = mergeQueueConfig(this._queueConfig, config)
    if (this._messageQueue) {
      this._messageQueue.config = this._queueConfig
    }
  }
}
