import Client from './client'
import { queryParameters } from './utils'

/**
 * ### ZClient API
 *
 * When you include the ZAF SDK on your website, you get access to the `ZClient` object.
 *
 * #### ZClient.init([callback(context)])
 *
 * Returns a [`client`](#client-object) object.
 *
 * ##### Arguments
 *
 *   * `callback(context)` (optional) a function called as soon as communication with
 *     the Zuper app is established. The callback receives a context object with
 *     data related to the Zuper app, including `currentAccount`, `currentUser`, and `location`
 *
 * Example:
 *
 * ```javascript
 * const client = ZClient.init((context) => {
 *   const currentUser = context.currentUser;
 *   console.log('Hi ' + currentUser.name);
 * });
 * ```
 */

const ZClient = {
  init: function (callback, loc) {
    loc = loc || window.location
    const queryParams = queryParameters(loc.search);
    const origin = queryParams.origin;
    const appGuid = queryParams.app_guid;

    // Early return optimization - check hash only if needed
    if (!origin || !appGuid) {
      const hashParams = queryParameters(loc.hash);
      const finalOrigin = origin || hashParams.origin;
      const finalAppGuid = appGuid || hashParams.app_guid;
      if (!finalOrigin || !finalAppGuid) { return false }

      const client = new Client({ origin: finalOrigin, appGuid: finalAppGuid })
      if (typeof callback === 'function') {
        client.on('app.registered', callback.bind(client))
      }
      return client
    }

    const client = new Client({ origin, appGuid })
    if (typeof callback === 'function') {
      client.on('app.registered', callback.bind(client))
    }

    return client
  }
}

export default ZClient
